-- Hunt Radar Hot Wheels clean catalog import
-- Generated from hotwheels_2026_clean.json. Public read-only catalog data.

create table if not exists public.hotwheels_catalog_items (
  id text primary key,
  model_name text not null,
  release_year integer not null,
  color text not null default '',
  image_url text,
  features text[] not null default '{}'::text[],
  rarity_segment text not null default 'regular' check (rarity_segment in (
    'regular',
    'silver_series',
    'premium',
    'treasure_hunt',
    'super_treasure_hunt',
    'zamac',
    'red_edition',
    'exclusive'
  )),
  created_at timestamptz not null default now(),
  updated_at timestamptz not null default now()
);

alter table public.hotwheels_catalog_items enable row level security;

drop policy if exists "hotwheels catalog readable" on public.hotwheels_catalog_items;
create policy "hotwheels catalog readable"
on public.hotwheels_catalog_items
for select
to anon, authenticated
using (true);

grant select on public.hotwheels_catalog_items to anon, authenticated;

on conflict (id) do update set
  model_name = excluded.model_name,
  release_year = excluded.release_year,
  color = excluded.color,
  image_url = excluded.image_url,
  features = excluded.features,
  rarity_segment = excluded.rarity_segment,
  updated_at = now();

-- Verification
select
  count(*) as imported_count,
  count(*) filter (where 'TH' = any(features)) as th_count,
  count(*) filter (where 'STH' = any(features)) as sth_count
from public.hotwheels_catalog_items;
